import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { Purchase } from '../models';
import { StoreApiService } from '../services/store-api.service';
import { AuthService } from '../services/auth.service';

@Component({
  selector: 'app-purchases-page',
  standalone: true,
  imports: [CommonModule, RouterLink],
  template: `
    <section class="hero">
      <h1>Mis Compras</h1>
    </section>

    <div *ngIf="loading" class="empty">Cargando compras...</div>
    <div *ngIf="error" class="error">{{ error }}</div>

    <ng-container *ngIf="!loading && !error">
      <div *ngIf="purchases.length === 0" class="empty">No has realizado ninguna compra.</div>

      <section class="grid" *ngIf="purchases.length > 0">
        <article class="card" *ngFor="let purchase of purchases">
          <h3 class="card__title">{{ purchase.nombre }}</h3>
          <p>{{ purchase.descripcion }}</p>
          <p class="card__meta">Comprado el {{ formatDate(purchase.fechaCompra) }}</p>
          <p><strong>S/ {{ purchase.precio | number:'1.2-2' }}</strong></p>
          <div style="display:flex; justify-content:flex-end; margin-top:1rem;">
            <a class="back-link" [routerLink]="['/producto', purchase.productoId]">Volver a comprar</a>
          </div>
        </article>
      </section>
    </ng-container>
  `,
})
export class PurchasesPageComponent implements OnInit {
  purchases: Purchase[] = [];
  loading = true;
  error = '';

  constructor(
    private readonly storeApi: StoreApiService,
    private readonly auth: AuthService,
  ) {}

  ngOnInit(): void {
    if (!this.auth.isAuthenticated) {
      this.error = 'Debes iniciar sesión para ver tus compras.';
      this.loading = false;
      return;
    }

    this.storeApi.getPurchases().subscribe({
      next: (response) => {
        this.purchases = response.compras;
        this.loading = false;
      },
      error: () => {
        this.error = 'No se pudieron cargar las compras.';
        this.loading = false;
      },
    });
  }

  formatDate(dateStr: string): string {
    const date = new Date(dateStr);
    return date.toLocaleDateString('es-PE');
  }
}
